  .filter-group { display: flex; flex-direction: column; gap: 8px; flex: 1; text-align: left; }
  .filter-group label { font-weight: 600; color: #444; font-size: 0.95rem; }
  input[type="range"] { accent-color: #673ab7; cursor: pointer; }
