  .rank-number { position: absolute; top: -15px; left: -10px; font-size: 3.5rem; font-weight: 900; color: #673ab7; text-shadow: 2px 2px 0px white, 4px 4px 10px rgba(0,0,0,0.15); z-index: 10; }
